const item = $json;

const subject = (item.subject || '').toLowerCase();
const body = (item.description || '').toLowerCase();
const email = (item.customer_email || '').toLowerCase();

// Common spam keywords
const spamKeywords = [
  'win money',
  'free gift',
  'click here',
  'urgent action',
  'lottery',
  'bitcoin',
  'crypto',
  'investment opportunity'
];

// Suspicious email domains
const spamDomains = [
  'tempmail',
  '10minutemail',
  'mailinator',
  'guerrillamail'
];

// Keyword match
const keywordSpam = spamKeywords.some(k =>
  subject.includes(k) || body.includes(k)
);

// Domain match
const domainSpam = spamDomains.some(d =>
  email.includes(d)
);

// Final spam decision
const isSpam = keywordSpam || domainSpam;

// If spam → stop workflow
if (isSpam) {
  return [];
}

// Not spam → continue
return [{ json: item }];

// Get email body from previous node
const emailBody = $json["description"].toLowerCase();

// Define keywords and corresponding tags
const keywordTags = {
  "refund": "refund",
  "damaged": "damaged",
  "late delivery": "late_delivery"
};

// Initialize tags array
let tags = [];

// Loop through keywords and add tags if found
for (const keyword in keywordTags) {
  if (emailBody.includes(keyword)) {
    tags.push(keywordTags[keyword]);
  }
}

// Return updated data
return [
  {
    json: {
      ...$json,
      tags
    }
  }
];

// Get all merged items
const items = $input.all();

// First item is always the email
const email = items[0].json;

// Remaining items are Zendesk tickets
const tickets = items.slice(1).map(i => i.json);

// Safety check
if (!email || !email.subject) {
  throw new Error('Missing email subject');
}

// Normalize function
const normalize = (str) =>
  str.trim().toLowerCase();

// Check if subject already exists in Zendesk
const isDuplicate = tickets.some(ticket =>
  ticket.subject &&
  normalize(ticket.subject) === normalize(email.subject)
);

// If duplicate → stop workflow
if (isDuplicate) {
  return [];
}

// If NOT duplicate → allow ticket creation
return [
  {
    json: email
  }
];
